private val eventPrefix = "cassandra.save" private val meterPrefix = "cassandra-save" private var recordsToBeSent: Counter? = null private var timeToSuccess: Timer? = null private var timeToFailure: Timer? = null private var savedDocuments: Counter? = null private var failedDocuments: Counter? = null
override suspend fun start(context: StepStartStopContext) { meterRegistry?.apply { val tags = context.toMetersTags() recordsToBeSent = counter("$meterPrefix-saving-documents", tags) timeToSuccess = timer("$meterPrefix-time-to-response", tags) timeToFailure = timer("$meterPrefix-time-to-failure", tags) savedDocuments = counter("$meterPrefix-saved-documents", tags) failedDocuments = counter("$meterPrefix-failed-documents", tags) } }
override suspend fun stop(context: StepStartStopContext) { meterRegistry?.apply { remove(recordsToBeSent!!) remove(timeToSuccess!!) remove(timeToFailure!!) remove(savedDocuments!!) remove(failedDocuments!!) recordsToBeSent = null timeToSuccess = null timeToFailure = null savedDocuments = null failedDocuments = null } }

